// Trigger a cutscene from C++
UPROPERTY(EditAnywhere)
ALevelSequenceActor* CutsceneActor;

void AMyTrigger::PlayCutscene() {
    if (CutsceneActor) {
        ULevelSequencePlayer* Player = CutsceneActor->GetSequencePlayer();
        if (Player) {
            // Disable player input during cutscene
            APlayerController* PC = GetWorld()->GetFirstPlayerController();
            PC->SetInputMode(FInputModeUIOnly());
            PC->SetShowMouseCursor(false);

            // Bind to finished event
            Player->OnFinished.AddDynamic(this, &AMyTrigger::OnCutsceneFinished);

            Player->Play();
        }
    }
}

void AMyTrigger::OnCutsceneFinished() {
    // Restore player input
    APlayerController* PC = GetWorld()->GetFirstPlayerController();
    PC->SetInputMode(FInputModeGameOnly());
}
